#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

struct Edge{
	int u,v,w;
	bool operator<(Edge x)const{
		return w<x.w;
	}
}edge[N];

struct Pr{
	int to,val;
	bool operator<(Pr x)const{
		return val<x.val;
	}
};

struct Node{
	int val,res,tag;
}t[N<<2];

int n,m,f[N],v[N],ans[N],ff[N];
int fa[N],dep[N],son[N],sz[N],top[N],dfn[N],w[N],num;
bool b[N],inv[N];
vector<Pr> e[N];

int father(int x){
	return f[x]==x?x:f[x]=father(f[x]);
}

int father2(int x){
	return ff[x]==x?x:ff[x]=father2(ff[x]);
}

void dfs1(int x,int lst){
	fa[x]=lst;
	dep[x]=dep[lst]+1;
	sz[x]=1;
	for(auto y:e[x])
		if(y.to!=lst){
			v[y.to]=y.val;
			dfs1(y.to,x);
			sz[x]+=sz[y.to];
			if(sz[y.to]>sz[son[x]]) son[x]=y.to;
		}
}

void dfs2(int x,int topx){
	top[x]=topx;
	dfn[x]=++num;
	w[num]=x;
	if(son[x])
		dfs2(son[x],topx);
	for(auto y:e[x])
		if(y.to!=fa[x] && y.to!=son[x])
			dfs2(y.to,y.to);
}

void build(int cur,int l,int r){
	if(l==r){
		t[cur].val=v[w[l]];
		t[cur].res=ans[w[l]];
		t[cur].tag=2e9;
		return;
	}
	int mid=l+r>>1;
	build(cur*2,l,mid);
	build(cur*2+1,mid+1,r);
	t[cur].val=min(t[cur*2].val,t[cur*2+1].val);
	t[cur].res=min(t[cur*2].res,t[cur*2+1].res);
	t[cur].tag=2e9;
}

int LCA(int x,int y){
	while(top[x]!=top[y]){
		if(dep[top[x]]<dep[top[y]]) swap(x,y);
		x=fa[top[x]];
	}
	return dep[x]<dep[y]?x:y;
}

void pushdown(int cur){
	if(t[cur].tag<2e9){
		t[cur*2].tag=min(t[cur*2].tag,t[cur].tag);
		t[cur*2+1].tag=min(t[cur*2+1].tag,t[cur].tag);
		t[cur*2].res=min(t[cur*2].res,t[cur].tag);
		t[cur*2+1].res=min(t[cur*2+1].res,t[cur].tag);
		t[cur].tag=2e9;
	}
} 

void modify(int cur,int l,int r,int x,int tp){
	if(l==r){
		if(tp==0)
			t[cur].val=v[w[l]];
		else
			t[cur].res=ans[w[l]];
		t[cur].tag=2e9;
		return;
	}
    pushdown(cur);
	int mid=l+r>>1;
	if(x<=mid)
		modify(cur*2,l,mid,x,tp);
	else
		modify(cur*2+1,mid+1,r,x,tp);
	t[cur].val=min(t[cur*2].val,t[cur*2+1].val);
	t[cur].res=min(t[cur*2].res,t[cur*2+1].res); 
}

void modify(int cur,int l,int r,int x,int y,int k){
	if(x<=l && r<=y){
		t[cur].res=min(t[cur].res,k);
		t[cur].tag=min(t[cur].tag,k);
		return; 
	} 
	pushdown(cur);
	int mid=l+r>>1;
	if(x<=mid) modify(cur*2,l,mid,x,y,k);
	if(y>mid) modify(cur*2+1,mid+1,r,x,y,k);
	t[cur].res=min(t[cur*2].res,t[cur*2+1].res);
}

int query(int cur,int l,int r,int x,int y){
	if(x<=l && r<=y)
		return t[cur].val;
	pushdown(cur);
	int mid=l+r>>1,res=1e9;
	if(x<=mid)
		res=min(res,query(cur*2,l,mid,x,y));
	if(y>mid)
		res=min(res,query(cur*2+1,mid+1,r,x,y));
	return res;
}

void Merge(int x,int y){
	int fx=father(x),fy=father(y);
	if(fx!=fy){
		if(dep[fx]>dep[fy]) swap(fx,fy);
		f[fy]=fx,v[fx]=min(v[fx],v[fy]);
		modify(1,1,n,dfn[fx],0);
	}
}

int ask(int x){
	int res=1e9;
	while(x){
		res=min(res,query(1,1,n,dfn[top[x]],dfn[x]));
		x=fa[top[x]];
	}
	return res;
}

void dfs3(int x,int len){
	ans[x]=ask(x)+len;
	modify(1,1,n,dfn[x],1);
	for(auto y:e[x]){
		if(y.to==fa[x])
			continue;
		if(!inv[y.to])
			break;
		dfs3(y.to,len);
	}
}

void Update(int cur,int l,int r){
	if(l==r){
		ans[w[l]]=t[cur].res;
		return;
	}
	pushdown(cur);
	int mid=l+r>>1;
	Update(cur*2,l,mid);
	Update(cur*2+1,mid+1,r);
}

int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++)
		scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
	sort(edge+1,edge+m+1);
	for(int i=1;i<=n;i++) f[i]=i;
	for(int i=1;i<=m;i++){
		int fu=father(edge[i].u),fv=father(edge[i].v);
		if(fu!=fv){
			b[i]=1;
			f[fv]=fu;
			e[edge[i].u].push_back({edge[i].v,edge[i].w});
			e[edge[i].v].push_back({edge[i].u,edge[i].w});
		}
	}
	v[1]=1e9;
	dfs1(1,0);
	dfs2(1,1);
	for(int i=1;i<=n;i++){
		f[i]=ff[i]=i;
		ans[i]=2e9;
	}
	build(1,1,n);
	for(int i=1;i<=m;i++){
		int x=edge[i].u,y=edge[i].v,w=edge[i].w;
		if(b[i]){
			if(dep[x]<dep[y]) swap(x,y);
			inv[x]=1;
			int fx=father2(x),fy=father2(y);
			ff[fy]=fx;
			if(father2(x)==father2(1)){
				dfs3(x,w);
			}
		}else{
			int lca=LCA(x,y);
			for(int p=father(x);dep[p]>dep[lca];p=father(fa[p]))
				Merge(p,fa[p]);
			for(int p=father(y);dep[p]>dep[lca];p=father(fa[p]))
				Merge(p,fa[p]);
			int p=father(x);
			modify(1,1,n,dfn[p],dfn[p]+sz[p]-1,v[p]+w);
		}
	}
	Update(1,1,n);
	for(int i=2;i<=n;i++)
		printf("%d\n",ans[i]);
	return 0;
}
